<template>
  <div class="main">
      <NavBarMobile v-if="isMobileDevice"></NavBarMobile>
      <HeaderMobile v-if="isMobileDevice"></HeaderMobile>
      <HeaderDevice v-else></HeaderDevice>
      <router-view />
  </div>
</template>

<script>

import NavBarMobile from './views/Mobile/NavBarItem.vue'
import HeaderMobile from './views/Mobile/HeaderItem.vue'
import HeaderDevice from './views/Device/HeaderItem.vue'

export default {
  name: 'App',
  components: {
    NavBarMobile,
    HeaderMobile,
    HeaderDevice
  },
  data () {
    return {
      isMobileDevice: this.$utils.isMobile()
    }
  },
  created () {
    this.updateDeviceType()
  },
  methods: {
    updateDeviceType () {
      if (this.isMobileDevice) {
        this.Header = HeaderMobile
        this.NavBar = NavBarMobile
      } else {
        this.Header = HeaderDevice
      }
    }
  }
}
</script>

<style lang="less" scoped>
.main {
  background-color: #f4f6f9;
}
</style>
