import Vue from 'vue'
import VueRouter from 'vue-router'
import HomePageMobile from '@/views/Mobile/HomePageItem.vue'
import HomePageDevice from '@/views/Device/HomePageItem.vue'
import AboutPageMobile from '@/views/Mobile/AboutPageItem.vue'
import AboutPageDevice from '@/views/Device/AboutPageItem.vue'

Vue.use(VueRouter)

function isMobile () {
  return window.innerWidth <= 768
}

const routes = [
  {
    path: '/',
    redirect: '/home'
  },
  {
    path: '/home',
    name: 'home',
    component: isMobile() ? HomePageMobile : HomePageDevice
  },
  {
    path: '/about',
    name: 'about',
    component: isMobile() ? AboutPageMobile : AboutPageDevice
  }
]

const router = new VueRouter({
  routes
})

export default router
